    private updateToolbarVisibility(menuItem: SettingsMenu): void {
        let okToShowSettingsToolbar = false;
        switch (menuItem.pageType) {
            case PageTypes.CompaniesPortfolio:
            case PageTypes.CompaniesProject:
            case PageTypes.UserGroups:
            case PageTypes.UsersPortfolio:
                okToShowSettingsToolbar = true;
                break;

        }

        this.showSettingsToolbar.set(okToShowSettingsToolbar);
    }

    /**
     * Updates the iframe visibiity
     * @param menuItem
     */
    private updateIFrameVisibility(menuItem: SettingsMenu): void {
        // Try to get component if the menu has been converted.
        this.menuContentComponent = this.getMenuContentComponent(menuItem);

        // If it hasn't use the iframe.
        this.isIframeContent.set(this.menuContentComponent === null);

        // Ensure the component is updated
        this._cd.detectChanges();
    }

    /**
     * If using a component for this menu return it. Otherwise null
     * @param menuItem
     * @returns
     */
    private getMenuContentComponent(menuItem: SettingsMenu): Type<any> {
        switch (menuItem.pageType) {
            case PageTypes.TeamMembers:
                return TeamMembersComponent;
            case PageTypes.ChatbotPreferences:
                return ChatbotPreferencesComponent;

            default:
                return null;
        }
    }
}
